const commonEmojis = ['ًں¥€', 'ًںک­', 'ًں¤‍', 'ًں§€'];
const rareEmojis = ['âœ‌ï¸ڈ', 'ًں¤ھ', 'ًںچ©', 'ًںچ†', 'ًں•´ï¸ڈ', 'ًںڑ،'];

function getRandomInt(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
}

function getRandomItem(arr) {
    return arr[Math.floor(Math.random() * arr.length)];
}

function generateRandomSentence() {
    let subject = getRandomItem(wordMap.subjects);
    let action = getRandomItem(wordMap.actions);
    let consequence = getRandomItem(wordMap.consequences);

    subject = subject.replace(/\bUb\b/g, 'ًںڈپًں‡؛ًں‡¸Ubًںڈپًں‡؛ًں‡¸').replace(/\bUB\b/g, 'ًںڈپًں‡؛ًں‡¸UBًںڈپًں‡؛ًں‡¸');
    action = action.replace(/\bUb\b/g, 'ًںڈپًں‡؛ًں‡¸Ubًںڈپًں‡؛ًں‡¸').replace(/\bUB\b/g, 'ًںڈپًں‡؛ًں‡¸UBًںڈپًں‡؛ًں‡¸');
    consequence = consequence.replace(/\bUb\b/g, 'ًںڈپًں‡؛ًں‡¸Ubًںڈپًں‡؛ًں‡¸').replace(/\bUB\b/g, 'ًںڈپًں‡؛ًں‡¸UBًںڈپًں‡؛ًں‡¸');

    let baseSentence = `${subject} ${action} ${consequence}`;
    
    let words = baseSentence.split(' ');
    let emojiCount = getRandomInt(1, 7);
    
    for (let i = 0; i < emojiCount; i++) {
        let emojiPool = Math.random() < 0.9 ? commonEmojis : rareEmojis;
        let chosenEmoji = getRandomItem(emojiPool);
        let insertIndex = getRandomInt(0, words.length);
        words.splice(insertIndex, 0, chosenEmoji);
    }

    return words.join(' ');
}

const theublist = Array.from({ length: 100 }, () => generateRandomSentence());
